#nullable enable // autogenerated

using MVZ2.Vanilla.Properties;
using MVZ2Logic.Entities;
using PVZEngine;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.Projectiles
{
    [AutoEntityBehaviourDefinition(VanillaProjectileNames.cannonMissile)]
    public class CannonMissile : EntityBehaviourDefinition
    {
        public CannonMissile(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Init(Entity entity)
        {
            base.Init(entity);
            SetTimer(entity, new FrameTimer(GetFallTime(entity)));
        }
        public override void Update(Entity entity)
        {
            base.Update(entity);
            if (IsFalling(entity))
                return;
            var timer = GetTimer(entity);
            if (timer.RunToExpiredOrNull())
            {
                SetFalling(entity, true);
                var velocity = entity.Velocity;
                velocity = Vector3.down * velocity.magnitude;
                entity.Velocity = velocity;

                var position = GetTargetPosition(entity);
                position.y = entity.Level.GetGroundY(position.x, position.z) - velocity.y * GetFallTime(entity);
                entity.Position = position;
            }
        }
        public static bool IsFalling(Entity entity) => entity.GetProperty<bool>(PROP_FALLING);
        public static void SetFalling(Entity entity, bool value) => entity.SetProperty(PROP_FALLING, value);
        public static int GetFallTime(Entity entity) => entity.GetProperty<int>(PROP_FALL_TIME);
        public static void SetFallTime(Entity entity, int value) => entity.SetProperty(PROP_FALL_TIME, value);
        public static FrameTimer? GetTimer(Entity entity) => entity.GetProperty<FrameTimer>(PROP_TIMER);
        public static void SetTimer(Entity entity, FrameTimer? value) => entity.SetProperty(PROP_TIMER, value);
        public static Vector3 GetTargetPosition(Entity entity) => entity.GetProperty<Vector3>(PROP_TARGET_POSITION);
        public static void SetTargetPosition(Entity entity, Vector3 value) => entity.SetProperty(PROP_TARGET_POSITION, value);
        public const int VARIANT_NORMAL = 0;
        public const int VARIANT_DANGER = 1;
        public static readonly VanillaEntityPropertyMeta<bool> PROP_FALLING = new VanillaEntityPropertyMeta<bool>("falling");
        public static readonly VanillaEntityPropertyMeta<int> PROP_FALL_TIME = new VanillaEntityPropertyMeta<int>("fall_time", Ticks.FromSeconds(1));
        public static readonly VanillaEntityPropertyMeta<FrameTimer> PROP_TIMER = new VanillaEntityPropertyMeta<FrameTimer>("timer");
        public static readonly VanillaEntityPropertyMeta<Vector3> PROP_TARGET_POSITION = new VanillaEntityPropertyMeta<Vector3>("target_position");
    }
}
